#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        long long cur = 0;
        for (int i = 0; i < n; ++i) {
            long long x, l, f; scanf("%lld %lld %lld", &x, &l, &f);
            long long depart;
            if (cur <= x) depart = x;
            else if ((cur - x) % f == 0) depart = cur;
            else depart = x + ((cur - x + f - 1) / f) * f;
            cur = depart + l;
        }
        printf("%lld\n", cur);
    }
    return 0;
}

